// ── Helper: state badge class ─────────────────────────────────────────────

const ACTIVE_STATES = new Set([
  'cooking', 'brewing', 'painting', 'working', 'tending', 'reading', 'on',
]);
const DONE_STATES = new Set(['done', 'ready', 'open', 'cozy', 'resting']);

function badgeClass(state) {
  if (state === 'idle')         return 'idle';
  if (DONE_STATES.has(state))   return 'done';
  if (ACTIVE_STATES.has(state)) return 'active';
  return 'other';
}

// ── Log helper ────────────────────────────────────────────────────────────

function pushLog(objectId, fromState, toState, trigger) {
  log.unshift({ objectId, fromState, toState, trigger, time: simEngine.getSimTimeString() });
  if (log.length > MAX_LOG) log.length = MAX_LOG;
  logDirty = true;
}

function pushAILog(charLabel, action, target, dialogue) {
  log.unshift({ type: 'ai', charLabel, action, target, dialogue, time: simEngine.getSimTimeString() });
  if (log.length > MAX_LOG) log.length = MAX_LOG;
  logDirty = true;
}

// ── Manual interact (called from interaction buttons) ─────────────────────

window._dbInteract = function(objectId, action) {
  const obj = simEngine.objectEngine.getById(objectId);
  if (!obj) return;
  const from = obj.state;
  const ev = simEngine.objectEngine.interact(objectId, action);
  if (ev) {
    pushLog(objectId, from, ev.state, action);
    prevStateMap.set(objectId, ev.state);
    updateObjectCard(obj);
  }
};

// ── Build DOM cards (once) ────────────────────────────────────────────────

function initObjectCards() {
  const grid = document.getElementById('objects-grid');
  for (const obj of simEngine.objectEngine.getAll()) {
    const card = document.createElement('div');
    card.className = 'object-card';
    card.id = `obj-${obj.id}`;
    card.innerHTML = `
      <div class="object-card-header">
        <span class="object-name">${obj.name}</span>
        <span class="state-badge" id="badge-${obj.id}"></span>
      </div>
      <div class="position-hint">tile (${obj.tx}, ${obj.ty})</div>
      <div class="timer-bar" id="timerbar-${obj.id}" style="display:none">
        <div class="timer-fill" id="timerfill-${obj.id}" style="width:0%"></div>
      </div>
      <div class="timer-text" id="timertext-${obj.id}" style="display:none"></div>
      <div class="interactions" id="int-${obj.id}"></div>
    `;
    grid.appendChild(card);
    updateObjectCard(obj); // initial paint
  }
}

function updateObjectCard(obj) {
  const badge      = document.getElementById(`badge-${obj.id}`);
  const timerBar   = document.getElementById(`timerbar-${obj.id}`);
  const timerFill  = document.getElementById(`timerfill-${obj.id}`);
  const timerText  = document.getElementById(`timertext-${obj.id}`);
  const intDiv     = document.getElementById(`int-${obj.id}`);
  if (!badge) return;

  const prevState = badge.dataset.state;
  const stateChanged = prevState !== obj.state;

  if (stateChanged) {
    badge.textContent = obj.state;
    badge.className = `state-badge ${badgeClass(obj.state)}`;
    badge.dataset.state = obj.state;

    // Rebuild interaction buttons on state change
    const stateDef = obj.states[obj.state];
    const actions = Object.keys(stateDef?.transitions || {});
    intDiv.innerHTML = actions.map(a =>
      `<button onclick="window._dbInteract('${obj.id}','${a}')">${a}</button>`
    ).join('');
  }

  // Timer bar (update every frame regardless of state change)
  const stateDef = obj.states[obj.state];
  const hasTimer = !!(stateDef?.auto_next && obj.autoTimer > 0);
  if (hasTimer) {
    const totalMs = stateDef.auto_next.after * 1000;
    const pct = Math.max(0, Math.min(100, (1 - obj.autoTimer / totalMs) * 100));
    timerBar.style.display = '';
    timerFill.style.width  = `${pct.toFixed(1)}%`;
    timerText.style.display = '';
    timerText.textContent   = `${Math.ceil(obj.autoTimer / 1000)}s remaining`;
  } else {
    timerBar.style.display  = 'none';
    timerText.style.display = 'none';
  }
}

function initCharacterCards() {
  const grid = document.getElementById('characters-grid');
  simEngine.characters.forEach((char, i) => {
    const card = document.createElement('div');
    card.className = 'character-card';
    card.id = `char-${i}`;
    grid.appendChild(card);
    updateCharacterCard(char, i); // initial paint
  });
}

function updateCharacterCard(char, i) {
  const card = document.getElementById(`char-${i}`);
  if (!card) return;

  const targetName = char.interactTarget
    ? (simEngine.objectEngine.getById(char.interactTarget)?.name ?? char.interactTarget)
    : char.targetObjectId
      ? (simEngine.objectEngine.getById(char.targetObjectId)?.name ?? char.targetObjectId)
      : '—';

  // AI decision cooldown timer
  let cooldownHtml = '';
  if (aiEngine.enabled) {
    const remaining  = Math.max(0, aiEngine._timers.get(char.name) ?? aiEngine.decisionIntervalMs);
    const pct        = Math.max(0, Math.min(100, (1 - remaining / aiEngine.decisionIntervalMs) * 100));
    const secRemaining = Math.ceil(remaining / 1000);
    cooldownHtml = `
      <div class="char-row" style="margin-top:4px">
        <span>AI next</span>
        <span class="char-value">${secRemaining}s</span>
      </div>
      <div class="stat-bar">
        <div class="stat-fill ai-cooldown" style="width:${pct.toFixed(1)}%"></div>
      </div>
    `;
  }

  card.innerHTML = `
    <div class="character-name">${char.label}</div>
    <div class="char-row">
      <span>Action</span>
      <span class="action-badge ${char.action}">${char.action}</span>
    </div>
    <div class="char-row">
      <span>Position</span>
      <span class="char-value">(${Math.round(char.tx)}, ${Math.round(char.ty)})</span>
    </div>
    <div class="char-row">
      <span>Facing</span>
      <span class="char-value">${char.facing}</span>
    </div>
    <div class="char-row">
      <span>Target</span>
      <span class="char-value">${targetName}</span>
    </div>
    <div class="char-row" style="margin-top:4px">
      <span>Mood</span>
      <span class="char-value">${char.mood}</span>
    </div>
    <div class="stat-bar">
      <div class="stat-fill mood" style="width:${char.mood}%"></div>
    </div>
    <div class="char-row" style="margin-top:4px">
      <span>Energy</span>
      <span class="char-value">${char.energy}</span>
    </div>
    <div class="stat-bar">
      <div class="stat-fill energy" style="width:${char.energy}%"></div>
    </div>
    ${cooldownHtml}
  `;
}

function renderEventLog() {
  if (!logDirty) return;
  logDirty = false;

  const el = document.getElementById('event-log');
  if (log.length === 0) {
    el.innerHTML = '<div style="color:#555;padding:4px 0">No events yet.</div>';
    return;
  }
  el.innerHTML = log.slice(0, 80).map(e => {
    if (e.type === 'ai') {
      const targetStr   = e.target   ? ` \u2192 ${e.target}` : '';
      const dialogueStr = e.dialogue ? ` \u201c${e.dialogue}\u201d` : '';
      return `
        <div class="log-entry ai">
          <span class="log-time">${e.time}</span>
          <span class="log-obj">${e.charLabel}</span>
          <span class="log-transition">${e.action}${targetStr}${dialogueStr}</span>
          <span class="log-tag ai">AI</span>
        </div>
      `;
